{
    CAMLparam1(v_trigger_num);
    CAMLlocal1(v_result);
    int trigger_num = Long_val(v_trigger_num);

    /* MAX_WALLS_PER_LINK = 10, so max output is 1 + 10 = 11 ints */
    int32_t buf[11];
    int len = 0;
    if (g_effect_sw_fetch_trigger_links) {
        g_effect_sw_fetch_trigger_links(trigger_num, buf, &len);
