{
#ifdef USE_OX_BRIDGE
	if (cd_ox_is_ready()) {
		static int iae_reg = 0;
		if (!iae_reg) {
			iae_reg = 1;
			cd_ox_register_init_ammo_energy_effects(
				/* fetch: [energy, shields, secondary_ammo_0, initial_energy, starting_shields, ndl, difficulty_level] */
				[](int32_t* out) {
					out[0] = Players[Player_num].energy;
