		if (Game_mode & GM_MULTI_COOP)
			multi_send_score();
#endif
		multi_send_position(Players[Player_num].objnum);
		multi_send_reappear();
	}

	if (Game_mode & GM_NETWORK)
		network_do_frame(1, 1);
