	Assert(Player_num > -1);
	Assert(Players[Player_num].objnum > -1);
	ConsoleObject = &Objects[Players[Player_num].objnum];
	Assert(ConsoleObject->type == OBJ_PLAYER);
	Assert(ConsoleObject->id == Player_num);
